#!/usr/bin/env python
"""
Bootstrap: Capture-Transform Scorer
REQUIRES: core/transform_enumerator.py (run bootstrap_capture_transform.py first)
Writes core/capture_transform_scorer.py + tests/test_capture_transform_scorer.py
Run: python bootstrap_capture_transform_scorer.py
"""
import base64, os, sys

if os.path.exists("core/universal_schema.py"): root = "."
elif os.path.exists("../core/universal_schema.py"): root = ".."
else: print("ERROR: Run from MABE root or one dir below."); sys.exit(1)

# Check dependency
dep = os.path.join(root, "core/transform_enumerator.py")
if not os.path.exists(dep):
    print("ERROR: core/transform_enumerator.py not found. Run bootstrap_capture_transform.py first.")
    sys.exit(1)

_p = os.path.join(root, "core/capture_transform_scorer.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

_p = os.path.join(root, "tests/test_capture_transform_scorer.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

print("Done. Run: python -m pytest tests/test_capture_transform_scorer.py -v")